#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        long long A[100005]; // K ≤ 10^5 fits in this static array
        for (int i = 0; i < K; ++i) scanf("%lld", &A[i]);
        char s[100005];
        for (int i = 0; i < N; ++i) {
            scanf("%s", s);
            long long sum = 0;
            for (int j = 0; j < K; ++j) if (s[j] == '1') sum += A[j];
            printf("%lld\n", sum);
        }
    }
    return 0;
}

