import sys

def main():
    data = sys.stdin.read().split()
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        A = [int(next(it)) for _ in range(K)]
        for _ in range(N):
            s = next(it)
            total = 0
            for idx,ch in enumerate(s):
                if ch == '1':
                    total += A[idx]
            out_lines.append(str(total))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

